/*
 * Vendored HTMX placeholder.
 *
 * Replace this file with the official minified release from
 *   https://unpkg.com/htmx.org@1.9.12/dist/htmx.min.js
 *
 * The placeholder defines a no-op htmx global so pages that reference
 * hx-get / hx-post still render without console errors. Production
 * deployments MUST replace this file before shipping; the testharness
 * does not exercise HTMX's runtime behaviour because tests assert the
 * server-rendered HTML, not the JS-driven interaction layer.
 */
(function (global) {
  "use strict";
  if (global.htmx) return;
  global.htmx = {
    version: "placeholder",
    on: function () {},
    off: function () {},
    process: function () {},
    trigger: function () {},
    ajax: function () {},
    config: {}
  };
})(typeof window !== "undefined" ? window : this);
